// Phong Lighting Model Implementation
// Input: surface point P, normal N, light position Lpos, viewer position Vpos
// Constants: Ka, Kd, Ks (reflectance), Ia, Id, Is (light intensities), n (shininess)

FUNCTION PhongIllumination(P, N, Lpos, Vpos, Ka, Kd, Ks, Ia, Id, Is, n)
BEGIN
 // Normalize vectors
 N = Normalize(N)
 L = Normalize(Lpos - P) // Light direction
 V = Normalize(Vpos - P) // View direction

 // Calculate reflection vector: R = 2(N·L)N - L
 dotLN = DotProduct(N, L)
 R = 2 * dotLN * N - L
 R = Normalize(R)

 // Ambient component: always present
 ambient = Ka * Ia

 // Diffuse component: Lambert's cosine law
 diffuseFactor = Max(dotLN, 0)
 diffuse = Kd * Id * diffuseFactor

 // Specular component: depends on view angle
 dotRV = DotProduct(R, V)
 specularFactor = Max(dotRV, 0)
 specular = Ks * Is * (specularFactor ^ n)

 // Total illumination
 I = ambient + diffuse + specular

 RETURN I
END

// Compute reflection vector R for incident light direction L
// Formula: R = 2(N·L)N - L
// Where N is surface normal, L is incident light direction (toward surface)

FUNCTION ComputeReflection(L, N)
BEGIN
 // Ensure N is normalized
 N = Normalize(N)
 // L should point TOWARD surface from light
 L = Normalize(L)

 // Calculate dot product
 dotProduct = DotProduct(N, L)

 // R = 2(N·L)N - L
 R = 2 * dotProduct * N - L
 R = Normalize(R)

 RETURN R
END

// Example usage with vectors:
// N = (0, 1, 0) [upward normal]
// L = (0, -1, 0) [light from above]
// R = (0, 1, 0) [reflected straight up]

// Phong illumination with multiple lights
// For each light, compute contribution and sum

FUNCTION PhongMultiLight(P, N, lights[], Vpos, material)
BEGIN
 // material: {Ka, Kd, Ks, n}
 // lights: array of {position, Ia, Id, Is, color}

 totalR = 0
 totalG = 0
 totalB = 0

 FOR EACH light IN lights DO
 // Direction to light
 L = Normalize(light.position - P)

 // View direction
 V = Normalize(Vpos - P)

 // Reflection vector
 dotLN = DotProduct(N, L)
 R = Normalize(2 * dotLN * N - L)

 // Ambient contribution
 ambient = material.Ka * light.Ia

 // Diffuse contribution
 diffuse = material.Kd * light.Id * Max(dotLN, 0)

 // Specular contribution
 dotRV = DotProduct(R, V)
 specular = material.Ks * light.Is * (Max(dotRV, 0) ^ material.n)

 // Add weighted color contribution
 intensity = ambient + diffuse + specular
 totalR = totalR + intensity * light.color.R
 totalG = totalG + intensity * light.color.G
 totalB = totalB + intensity * light.color.B
 END FOR

 RETURN Color(Clamp(totalR), Clamp(totalG), Clamp(totalB))
END
